SELECT DISTINCT v.make
FROM troubleshooting_sessions ts
INNER JOIN vehicles v ON ts.vehicle_id = v.vehicle_id;

SELECT session_id, SUM(cost) AS total_cost
FROM repairs
GROUP BY session_id;

SELECT issue_reported
FROM troubleshooting_sessions
WHERE status = 'Completed';

SELECT total_time_spent
FROM troubleshooting_sessions
WHERE session_id = 1;

SELECT step_id
FROM session_steps
WHERE result = 'No';

SELECT step_description
FROM diagnostic_steps
WHERE step_id = 0;

SELECT COUNT(*) 
FROM troubleshooting_sessions 
WHERE status = 'Completed';

SELECT SUM(part_cost) AS total_parts_cost
FROM repair_parts
WHERE repair_id = 0;

SELECT category, COUNT(*) AS article_count
FROM knowledge_base
GROUP BY category;

SELECT total_time_spent AS total_time_spent_minutes
FROM troubleshooting_sessions
WHERE session_id = 0;

SELECT COUNT(*) 
FROM diagnostic_steps 
WHERE step_type = 'Inspection' AND difficulty_level = 'Easy';
